using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF 9 breaking change: Cosmos doesn't support indexes — HasIndex now throws.
        // Removed: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);

        // EF 9 breaking change: default discriminator property renamed from "Discriminator" to "$type".
        // Preserve the old property name so existing documents are still found.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // EF 9 breaking change: default id format changed from "EntityType|Key" to just "Key".
        // Preserve the old format so existing documents (e.g. "Blog|1") still resolve.
        modelBuilder.Entity<Blog>().HasPartitionKey(b => b.Id);
        modelBuilder.Entity<Blog>().Property(b => b.Id)
            .ToJsonProperty("id")
            .HasValueGenerator<LegacyCosmosIdGenerator>();
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

