using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // BREAKING CHANGE 1: HasIndex now throws for Cosmos (was silently ignored).
        // Removed: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);

        // BREAKING CHANGE 2: Discriminator property renamed "$type" → keep old "Discriminator".
        // Also preserves discriminator *values* so existing documents match.
        modelBuilder.Entity<Blog>()
            .HasDiscriminator<string>("Discriminator")
            .HasValue<Blog>("Blog");

        // BREAKING CHANGE 3: id property no longer prefixed with discriminator.
        // Old format: "Blog|1", new default: "1".
        // Use a custom value generator to keep producing the old format.
        modelBuilder.Entity<Blog>()
            .Property(b => b.Id)
            .HasValueGenerator<PrefixedIdGenerator>();
    }
}

/// <summary>
/// Reproduces the EF Core 8 Cosmos id format: "{EntityTypeName}|{Key}".
